mapper.select:
SELECT p.id, p.patient_code, p.name, p.card_no, p.age, p.birthday, p.gender, p.phone, p.id_card, p.source, CASE COALESCE(m.member_type, p.member_level) WHEN '普通会员' THEN 'VIP1' WHEN '初级会员' THEN 'VIP1' WHEN '高级会员' THEN 'VIP2' WHEN '白银会员' THEN 'VIP3' WHEN '黄金会员' THEN 'VIP4' WHEN '钻石会员' THEN 'VIP5' WHEN '非会员' THEN '非会员' ELSE COALESCE(m.level_name, p.member_level, '非会员') END AS member_level, p.member_expire_date, p.nation, p.marriage, p.education, p.province_city, p.address, p.job, p.company, p.remark, p.operator, p.created_at, p.updated_at, p.deleted FROM clinic_patient p LEFT JOIN clinic_member m ON m.patient_id = p.id AND m.deleted = 0 WHERE p.deleted = 0
AND (p.patient_code LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%') OR p.phone LIKE CONCAT('%', #{keyword}, '%') OR p.card_no LIKE CONCAT('%', #{keyword}, '%') OR p.id_card LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE clinic_patient
SET deleted = 1, updated_at = NOW()
WHERE id = #{id}
